        for (let j = 1; j < N; j++) {
            const G = grid[i][j];

            // 1. From top (i-1, j)
            for (let x = 0; x < K_MAX; x++) {
                if (DP[i-1][j][x]) {
                    const newXOR = x ^ G;
                    DP[i][j][newXOR] = true;
                }
            }

            // 2. From left (i, j-1)
            for (let x = 0; x < K_MAX; x++) {
                if (DP[i][j-1][x]) {
                    const newXOR = x ^ G;
                    DP[i][j][newXOR] = true;
                }
            }
        }
    }

    // Find the minimum achievable XOR value at (M-1, N-1)
    for (let x = 0; x < K_MAX; x++) {
        if (DP[M-1][N-1][x]) {
            return x;
        }
    }

    // Should be unreachable given problem constraints
    return 0; 
